"use client";

import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import { Settings2, Users, FileText, Activity, RefreshCw, ArrowRight, ShieldAlert, Zap } from "lucide-react";
import SectionCard from "@/components/SectionCard";
import StatusBadge from "@/components/StatusBadge";
import { LoadingState, ErrorState } from "@/components/States";
import {
  fetchWorkers, fetchPolicies, fetchAuditLogs,
  SEED_WORKER_ID, type ApiWorker, type ApiPolicy, type AuditLogEntry
} from "@/lib/apiClient";

export default function AdminPage() {
  const [workers, setWorkers] = useState<ApiWorker[]>([]);
  const [policies, setPolicies] = useState<ApiPolicy[]>([]);
  const [recentLogs, setRecentLogs] = useState<AuditLogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const [ws, ps, auditRes] = await Promise.all([
        fetchWorkers(),
        fetchPolicies(SEED_WORKER_ID),
        fetchAuditLogs({ worker_id: SEED_WORKER_ID, limit: 10 }),
      ]);
      setWorkers(ws);
      setPolicies(ps);
      setRecentLogs(auditRes.data ?? []);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to load admin data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const activePolicy = policies.find((p) => p.status === "active");
  const worker = workers.find((w) => w.id === SEED_WORKER_ID) ?? workers[0];
  const totalSimulations = recentLogs.filter((l) => l.engine_name === "trigger").length;

  const decisionCounts = recentLogs.reduce<Record<string, number>>((acc, log) => {
    acc[log.decision] = (acc[log.decision] ?? 0) + 1;
    return acc;
  }, {});

  if (loading) return <LoadingState message="Loading system overview..." />;
  if (error) return <ErrorState message="Failed to load admin dashboard" detail={error} onRetry={load} />;

  return (
    <div className="space-y-5 max-w-[1200px] mx-auto pb-10">
      {/* Header */}
      <div className="flex items-center justify-between pb-2 border-b border-zinc-800/50">
        <div>
          <h1 className="text-2xl font-semibold text-white flex items-center gap-2">
            <Settings2 size={22} className="text-zinc-500" />
            System Admin
          </h1>
          <p className="text-[12px] text-zinc-500 mt-1">
            Registered workers ┬╖ Active policies ┬╖ Engine activity
          </p>
        </div>
        <button
          onClick={load}
          className="btn-secondary text-[11px] flex items-center gap-1.5"
        >
          <RefreshCw size={12} />
          Refresh
        </button>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: "Registered Workers", value: workers.length, icon: Users, accent: "emerald" },
          { label: "Active Policies", value: policies.filter((p) => p.status === "active").length, icon: FileText, accent: "sky" },
          { label: "Total Policies", value: policies.length, icon: ShieldAlert, accent: "amber" },
          { label: "Audit Log Entries", value: recentLogs.length, icon: Activity, accent: "violet" },
        ].map((stat) => (
          <div key={stat.label} className="card p-4">
            <div className="flex items-center justify-between mb-2">
              <p className="text-[10px] uppercase tracking-widest text-zinc-500">{stat.label}</p>
              <stat.icon size={14} className="text-zinc-600" />
            </div>
            <p className={`text-3xl font-bold font-mono ${
              stat.accent === "emerald" ? "text-emerald-400" :
              stat.accent === "sky" ? "text-sky-400" :
              stat.accent === "amber" ? "text-amber-400" :
              "text-violet-400"
            }`}>
              {stat.value}
            </p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-5">
        {/* Workers Table */}
        <div className="lg:col-span-7 space-y-4">
          <SectionCard
            title="Registered Workers"
            badge={<span className="text-[10px] text-zinc-500 font-mono">{workers.length} total</span>}
          >
            {workers.length === 0 ? (
              <p className="text-[12px] text-zinc-600 text-center py-6">No workers registered yet.</p>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-zinc-800/40">
                      {["Worker", "Platform", "Zone", "Vehicle"].map((h) => (
                        <th key={h} className="text-left py-2 px-3 text-[10px] font-mono text-zinc-600 uppercase tracking-widest">
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {workers.map((w) => (
                      <tr key={w.id} className="border-b border-zinc-800/30 hover:bg-zinc-800/10">
                        <td className="py-3 px-3">
                          <div className="flex items-center gap-2">
                            <div className="w-7 h-7 rounded-full bg-zinc-800 flex items-center justify-center text-[11px] font-mono text-zinc-400">
                              {w.name.charAt(0)}
                            </div>
                            <div>
                              <p className="text-[12px] font-medium text-zinc-200">{w.name}</p>
                              <p className="text-[10px] font-mono text-zinc-600">{w.id.substring(0, 8)}ΓÇª</p>
                            </div>
                          </div>
                        </td>
                        <td className="py-3 px-3 text-[11px] text-zinc-400">{w.platform}</td>
                        <td className="py-3 px-3 text-[11px] text-zinc-400">
                          {w.zones?.name ?? w.zone_id.substring(0, 8)}
                          {w.zones && <span className="text-zinc-600 ml-1">┬╖ {w.zones.zri}x</span>}
                        </td>
                        <td className="py-3 px-3 text-[11px] text-zinc-400">{w.vehicle_type}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
            <div className="mt-3 pt-3 border-t border-zinc-800/40">
              <Link href="/register" className="btn-secondary text-[11px] flex items-center gap-1.5 w-fit">
                <Users size={11} />
                Register New Worker
              </Link>
            </div>
          </SectionCard>

          {/* Policies Table */}
          <SectionCard
            title="Policies"
            badge={<span className="text-[10px] text-zinc-500 font-mono">{policies.length} total</span>}
          >
            {policies.length === 0 ? (
              <div className="text-center py-6">
                <p className="text-[12px] text-zinc-600">No policies found.</p>
                <Link href="/policy" className="btn-secondary text-[11px] mt-3 inline-flex items-center gap-1.5">
                  Create Policy ΓåÆ
                </Link>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-zinc-800/40">
                      {["ID", "Premium", "Limit", "BWE", "Status"].map((h) => (
                        <th key={h} className="text-left py-2 px-3 text-[10px] font-mono text-zinc-600 uppercase tracking-widest">
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {policies.map((p) => (
                      <tr key={p.id} className="border-b border-zinc-800/30 hover:bg-zinc-800/10">
                        <td className="py-3 px-3 text-[10px] font-mono text-zinc-600">{p.id.substring(0, 8)}ΓÇª</td>
                        <td className="py-3 px-3 text-[12px] font-mono text-emerald-400">Γé╣{p.weekly_premium}</td>
                        <td className="py-3 px-3 text-[12px] font-mono text-sky-400">Γé╣{p.coverage_limit}</td>
                        <td className="py-3 px-3 text-[11px] font-mono text-zinc-400">Γé╣{p.bwe}</td>
                        <td className="py-3 px-3">
                          <StatusBadge status={p.status === "active" ? "active" : "review"} />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </SectionCard>
        </div>

        {/* Right: Worker Detail + Recent Logs */}
        <div className="lg:col-span-5 space-y-4">
          {/* Active Worker Context */}
          {worker && (
            <SectionCard title="Active Worker Context">
              <div className="space-y-3">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-zinc-800 border border-zinc-700 flex items-center justify-center text-zinc-300 font-mono font-semibold">
                    {worker.name.charAt(0)}
                  </div>
                  <div>
                    <p className="text-[14px] font-semibold text-zinc-200">{worker.name}</p>
                    <p className="text-[11px] font-mono text-zinc-500">{worker.platform}</p>
                  </div>
                  <StatusBadge status="active" />
                </div>
                {activePolicy && (
                  <div className="grid grid-cols-2 gap-2 pt-2 border-t border-zinc-800/40">
                    <div className="card p-3">
                      <p className="text-[9px] text-zinc-600 uppercase tracking-wider">Premium</p>
                      <p className="text-[14px] font-mono text-emerald-400 mt-0.5">Γé╣{activePolicy.weekly_premium}</p>
                    </div>
                    <div className="card p-3">
                      <p className="text-[9px] text-zinc-600 uppercase tracking-wider">Cap</p>
                      <p className="text-[14px] font-mono text-sky-400 mt-0.5">Γé╣{activePolicy.coverage_limit}</p>
                    </div>
                  </div>
                )}
                <div className="flex gap-2 flex-wrap pt-1">
                  <Link href="/simulate" className="btn-primary text-[11px] flex items-center gap-1.5">
                    <Zap size={11} />
                    Run Simulation
                  </Link>
                  <Link href="/policy" className="btn-secondary text-[11px]">
                    View Policy
                  </Link>
                </div>
              </div>
            </SectionCard>
          )}

          {/* Engine Decision Summary */}
          {Object.keys(decisionCounts).length > 0 && (
            <SectionCard title="Decision Summary">
              <div className="space-y-1.5">
                {Object.entries(decisionCounts).map(([decision, count]) => (
                  <div key={decision} className="flex justify-between items-center py-1.5 border-b border-zinc-800/30 last:border-0">
                    <span className="text-[11px] font-mono text-zinc-400">{decision}</span>
                    <span className="text-[11px] font-mono text-zinc-300 font-medium">{count}├ù</span>
                  </div>
                ))}
              </div>
            </SectionCard>
          )}

          {/* Recent Audit Entries */}
          <SectionCard
            title="Recent Audit Entries"
            headerRight={
              <Link href="/audit" className="text-[10px] text-zinc-500 hover:text-zinc-300 flex items-center gap-1">
                View All <ArrowRight size={10} />
              </Link>
            }
          >
            {recentLogs.length === 0 ? (
              <p className="text-[12px] text-zinc-600 py-4 text-center">No audit logs yet.</p>
            ) : (
              <div className="space-y-1">
                {recentLogs.slice(0, 6).map((log) => (
                  <div key={log.id} className="flex items-start gap-2 py-2 border-b border-zinc-800/30 last:border-0">
                    <span className={`text-[9px] font-mono px-1.5 py-0.5 rounded border flex-shrink-0 mt-0.5 ${
                      log.engine_name === "trigger" ? "text-sky-400 border-sky-400/20 bg-sky-400/10" :
                      log.engine_name === "fraud" ? "text-red-400 border-red-400/20 bg-red-400/10" :
                      log.engine_name === "payout" ? "text-emerald-400 border-emerald-400/20 bg-emerald-400/10" :
                      "text-violet-400 border-violet-400/20 bg-violet-400/10"
                    }`}>
                      {log.engine_name}
                    </span>
                    <div className="min-w-0 flex-1">
                      <p className="text-[11px] font-mono text-zinc-300 truncate">{log.decision}</p>
                      <p className="text-[10px] text-zinc-600 truncate mt-0.5">{log.message.substring(0, 60)}ΓÇª</p>
                    </div>
                    <span className="text-[9px] text-zinc-700 font-mono flex-shrink-0">
                      {new Date(log.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </SectionCard>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import {
  MapPin, Activity, ShieldCheck, ArrowRight, Zap, UserPlus,
  FileText, ClipboardList, CloudRain, RefreshCw, DollarSign,
  CheckCircle2, AlertTriangle
} from "lucide-react";
import SectionCard from "@/components/SectionCard";
import StatusBadge from "@/components/StatusBadge";
import KeyMetricCard from "@/components/KeyMetricCard";
import { LoadingState, ErrorState } from "@/components/States";
import ProgressBar from "@/components/ProgressBar";
import {
  fetchWorkers, fetchPolicies, fetchPremiumQuote, fetchAuditLogs,
  SEED_WORKER_ID, type ApiWorker, type ApiPolicy, type ApiPremiumResult, type AuditLogEntry
} from "@/lib/apiClient";

const engineBadge: Record<string, string> = {
  trigger:     "text-sky-400 bg-sky-400/10 border-sky-400/20",
  attribution: "text-violet-400 bg-violet-400/10 border-violet-400/20",
  fraud:       "text-red-400 bg-red-400/10 border-red-400/20",
  payout:      "text-emerald-400 bg-emerald-400/10 border-emerald-400/20",
  orchestrator:"text-amber-400 bg-amber-400/10 border-amber-400/20",
};

export default function DashboardPage() {
  const [worker, setWorker] = useState<ApiWorker | null>(null);
  const [policy, setPolicy] = useState<ApiPolicy | null>(null);
  const [quote, setQuote] = useState<ApiPremiumResult | null>(null);
  const [recentLogs, setRecentLogs] = useState<AuditLogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const [workers, policies, premiumRes, auditRes] = await Promise.all([
        fetchWorkers(),
        fetchPolicies(SEED_WORKER_ID),
        fetchPremiumQuote(SEED_WORKER_ID),
        fetchAuditLogs({ worker_id: SEED_WORKER_ID, limit: 8 }),
      ]);
      setWorker(workers.find((w) => w.id === SEED_WORKER_ID) ?? workers[0] ?? null);
      setPolicy(policies.find((p) => p.status === "active") ?? policies[0] ?? null);
      setQuote(premiumRes);
      setRecentLogs(auditRes.data ?? []);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  if (loading) return <LoadingState message="Loading dashboard..." />;
  if (error) return <ErrorState message="Dashboard load failed" detail={error} onRetry={load} />;

  const premium = policy?.weekly_premium ?? quote?.premium ?? 0;
  const coverage = policy?.coverage_limit ?? quote?.coverage_limit ?? 0;
  const bwe = policy?.bwe ?? quote?.data?.base_weekly_exposure ?? 0;
  const zri = worker?.zones?.zri ?? 1.18;

  // Find latest payout log
  const latestPayout = recentLogs.find((l) => l.engine_name === "payout");
  const latestTrigger = recentLogs.find((l) => l.engine_name === "trigger");

  return (
    <div className="space-y-5 max-w-[1280px] mx-auto pb-10">
      {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
      <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 pb-2 border-b border-zinc-800/50">
        {worker ? (
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-md bg-zinc-800 border border-zinc-700/50 flex items-center justify-center text-2xl font-semibold text-zinc-300 font-mono">
              {worker.name.charAt(0)}
            </div>
            <div>
              <div className="flex items-center gap-3">
                <h1 className="text-2xl font-semibold tracking-tight text-white">{worker.name}</h1>
                <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-xs font-medium">
                  <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                  PROTECTED
                </div>
              </div>
              <div className="flex items-center gap-3 mt-1.5 text-[11px] text-zinc-400 font-mono">
                <span className="flex items-center gap-1">
                  <MapPin size={11} className="text-zinc-500" />
                  {worker.zones?.name ?? worker.zone_id.substring(0, 8)} ┬╖ {worker.zones?.city}
                </span>
                <span className="text-zinc-700">|</span>
                <span>{worker.platform}</span>
                <span className="text-zinc-700">|</span>
                <span>{worker.vehicle_type}</span>
              </div>
            </div>
          </div>
        ) : (
          <div>
            <h1 className="text-2xl font-semibold text-white">Dashboard</h1>
            <p className="text-[12px] text-zinc-500 mt-1">No worker found. Register one to get started.</p>
          </div>
        )}
        <div className="flex items-center gap-2">
          <button onClick={load} className="btn-secondary text-[11px] flex items-center gap-1.5">
            <RefreshCw size={12} />
            Refresh
          </button>
        </div>
      </div>

      {/* ΓöÇΓöÇ Key Metrics ΓöÇΓöÇ */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <KeyMetricCard
          label="Weekly Premium"
          value={premium ? `Γé╣${premium}` : "ΓÇö"}
          sub={policy ? "Active policy" : "No active policy"}
          accent={policy ? "emerald" : "zinc"}
        />
        <KeyMetricCard
          label="Coverage Cap"
          value={coverage ? `Γé╣${coverage}` : "ΓÇö"}
          sub="Maximum weekly payout"
          accent="sky"
        />
        <KeyMetricCard
          label="Zone Risk Index"
          value={zri.toFixed(2)}
          unit="├ù ZRI"
          sub={worker?.zones?.name ?? "ΓÇö"}
          accent="amber"
        />
        <KeyMetricCard
          label="Base Weekly Earning"
          value={bwe ? `Γé╣${bwe.toFixed(0)}` : "ΓÇö"}
          sub="Historical median"
          accent="zinc"
        />
      </div>

      {/* ΓöÇΓöÇ Main Grid ΓöÇΓöÇ */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-5">
        {/* LEFT COLUMN */}
        <div className="lg:col-span-7 space-y-5">

          {/* Policy Panel */}
          <SectionCard
            title="Active Policy"
            badge={policy
              ? <StatusBadge status="active" />
              : <span className="text-[10px] text-amber-400 bg-amber-400/10 px-2 py-0.5 rounded border border-amber-400/20">NO POLICY</span>
            }
            headerRight={
              <Link href="/policy" className="text-[10px] text-zinc-500 hover:text-zinc-300 flex items-center gap-1">
                Manage <ArrowRight size={10} />
              </Link>
            }
            className={policy ? "border-emerald-500/10" : "border-amber-500/10"}
          >
            {policy ? (
              <div>
                <div className="grid grid-cols-3 gap-4 mb-4">
                  <div>
                    <p className="text-[10px] text-zinc-600 uppercase tracking-widest mb-1">Weekly Premium</p>
                    <p className="data-value text-2xl font-semibold text-white">Γé╣{policy.weekly_premium}</p>
                  </div>
                  <div className="border-l border-zinc-800/50 pl-4">
                    <p className="text-[10px] text-zinc-600 uppercase tracking-widest mb-1">Coverage Cap</p>
                    <p className="data-value text-2xl font-semibold text-white">Γé╣{policy.coverage_limit}</p>
                  </div>
                  <div className="border-l border-zinc-800/50 pl-4">
                    <p className="text-[10px] text-zinc-600 uppercase tracking-widest mb-1">BWE (Base)</p>
                    <p className="data-value text-2xl font-semibold text-white">Γé╣{policy.bwe}</p>
                  </div>
                </div>
                {quote?.data && (
                  <div className="pt-3 border-t border-zinc-800/40">
                    <p className="text-[10px] text-zinc-600 uppercase tracking-widest mb-3">Risk Factors</p>
                    <div className="space-y-2.5">
                      <ProgressBar value={quote.data.zone_multiplier / 2} label={`Zone Multiplier (ZRI: ${quote.data.zone_multiplier.toFixed(2)})`} color="amber" size="sm" />
                      <ProgressBar value={quote.data.work_intensity_factor / 2} label={`Work Intensity (${quote.data.work_intensity_factor.toFixed(2)}├ù)`} color="sky" size="sm" />
                      <ProgressBar value={quote.data.time_exposure_factor / 2} label={`Time Exposure (${quote.data.time_exposure_factor.toFixed(2)}├ù)`} color="emerald" size="sm" />
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="text-center py-6">
                <AlertTriangle size={24} className="text-amber-400 mx-auto mb-3" />
                <p className="text-[13px] text-zinc-400">No active policy found</p>
                <Link href="/policy" className="btn-primary text-[12px] mt-4 inline-flex items-center gap-2">
                  <FileText size={13} />
                  Set Up Policy ΓåÆ
                </Link>
              </div>
            )}
          </SectionCard>

          {/* Recent Audit Trail */}
          <SectionCard
            title="Recent Engine Activity"
            subtitle="Latest audit log entries from engine runs"
            headerRight={
              <Link href="/audit" className="text-[10px] text-zinc-500 hover:text-zinc-300 flex items-center gap-1">
                View All <ArrowRight size={10} />
              </Link>
            }
          >
            {recentLogs.length === 0 ? (
              <p className="text-[12px] text-zinc-600 py-4 text-center">
                No simulations run yet.{" "}
                <Link href="/simulate" className="text-emerald-400 hover:underline">Run one now ΓåÆ</Link>
              </p>
            ) : (
              <div className="space-y-1">
                {recentLogs.map((log) => (
                  <div key={log.id} className="flex items-center gap-3 py-2.5 border-b border-zinc-800/30 last:border-0">
                    <span className={`text-[9px] font-mono px-1.5 py-0.5 rounded border flex-shrink-0 ${engineBadge[log.engine_name] ?? "text-zinc-400 border-zinc-800"}`}>
                      {log.engine_name}
                    </span>
                    <p className="text-[11px] font-mono text-zinc-300 font-medium">{log.decision}</p>
                    <p className="text-[10px] text-zinc-600 flex-1 truncate">{log.message.substring(0, 55)}ΓÇª</p>
                    <span className="text-[9px] font-mono text-zinc-700 flex-shrink-0">
                      {new Date(log.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </SectionCard>
        </div>

        {/* RIGHT COLUMN */}
        <div className="lg:col-span-5 space-y-5">
          {/* Quick Actions */}
          <SectionCard title="Quick Actions">
            <div className="grid grid-cols-2 gap-3">
              {[
                { href: "/simulate", icon: CloudRain, label: "Simulate Rain", desc: "Run disruption", color: "sky" },
                { href: "/policy",   icon: FileText,   label: "Manage Policy", desc: "View premium",  color: "emerald" },
                { href: "/register", icon: UserPlus,   label: "Register",      desc: "Add worker",    color: "violet" },
