"use client";

import { useEffect, useRef, useState } from "react";
import type { SimulationResult } from "@/lib/mockData";

interface SimulationTerminalProps {
  lines: SimulationResult[];
  isRunning: boolean;
  title?: string;
}

const typeColors: Record<string, string> = {
  info: "text-zinc-400",
  data: "text-sky-400",
  pass: "text-emerald-400",
  fail: "text-red-400",
  result: "text-amber-300",
};

const stageColors: Record<string, string> = {
  INGEST: "text-sky-500",
  NORMALIZE: "text-violet-400",
  RELIABILITY: "text-indigo-400",
  TCS: "text-amber-400",
  UNCERTAINTY: "text-orange-400",
  DECISION: "text-emerald-400",
  EXPOSURE: "text-cyan-400",
  ATTRIBUTION: "text-purple-400",
  FRAUD: "text-rose-400",
  PAYOUT: "text-emerald-500",
  SETTLE: "text-green-400",
  AUDIT: "text-zinc-500",
  INIT: "text-zinc-400",
  TRIGGER: "text-amber-400",
  RESERVE: "text-teal-400",
  PERF: "text-blue-400",
};

export default function SimulationTerminal({
  lines,
  isRunning,
  title = "output",
}: SimulationTerminalProps) {
  const [visibleCount, setVisibleCount] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isRunning) {
      setVisibleCount(0);
      return;
    }

    setVisibleCount(0);
    const interval = setInterval(() => {
      setVisibleCount((prev) => {
        if (prev >= lines.length) {
          clearInterval(interval);
          return prev;
        }
        return prev + 1;
      });
    }, 180);

    return () => clearInterval(interval);
  }, [isRunning, lines.length]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [visibleCount]);

  const visibleLines = lines.slice(0, visibleCount);

  return (
    <div className="inset-terminal flex flex-col h-full">
      {/* Terminal chrome */}
      <div className="flex items-center gap-2 px-3 py-2 border-b border-zinc-800/50">
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-zinc-700" />
          <div className="w-2.5 h-2.5 rounded-full bg-zinc-700" />
          <div className="w-2.5 h-2.5 rounded-full bg-zinc-700" />
        </div>
        <span className="text-[10px] text-zinc-600 ml-2">{title}</span>
        {isRunning && visibleCount < lines.length && (
          <span className="ml-auto text-[10px] text-amber-500/60 animate-pulse">processing</span>
        )}
        {isRunning && visibleCount >= lines.length && (
          <span className="ml-auto text-[10px] text-emerald-500/60">complete</span>
        )}
      </div>

      {/* Output area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-3 min-h-[300px] max-h-[480px]">
        {!isRunning && visibleCount === 0 && (
          <div className="flex items-center justify-center h-full">
            <p className="text-zinc-700 text-xs">awaiting simulation input_</p>
          </div>
        )}

        {visibleLines.map((line, i) => (
          <div
            key={i}
            className="flex gap-2 leading-relaxed animate-fade-in"
          >
            <span className="text-zinc-600 flex-shrink-0 w-[52px] text-right">
              {line.timestamp}
            </span>
            <span className={`flex-shrink-0 w-[82px] text-right uppercase text-[10px] pt-[2px] ${stageColors[line.stage] || "text-zinc-500"}`}>
              [{line.stage}]
            </span>
            <span className={typeColors[line.type]}>
              {line.message}
            </span>
          </div>
        ))}

        {isRunning && visibleCount < lines.length && (
          <div className="flex gap-2 mt-0.5">
            <span className="text-zinc-600 w-[52px]" />
            <span className="text-zinc-600 w-[82px]" />
            <span className="text-zinc-600 animate-pulse">Γûî</span>
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * Pure mathematical utilities for AIPS parametric evaluations.
 */

export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function safeDivision(numerator: number, denominator: number, fallback: number = 0): number {
  if (denominator === 0 || isNaN(denominator)) return fallback;
  return numerator / denominator;
}

export function median(values: number[]): number {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

export function weightedAverage(items: any[], valueKey: string, weightKey: string): number {
  if (items.length === 0) return 0;
  let sumProduct = 0;
  let sumWeights = 0;
  for (const item of items) {
    const val = item[valueKey] || 0;
    const weight = item[weightKey] || 0;
    sumProduct += val * weight;
    sumWeights += weight;
  }
  return safeDivision(sumProduct, sumWeights, 0);
}

export function confidenceBlend(scores: number[], confidences: number[]): number {
  if (scores.length !== confidences.length || scores.length === 0) return 0;
  let sumProduct = 0;
  let sumConfidence = 0;
  for (let i = 0; i < scores.length; i++) {
    sumProduct += scores[i] * confidences[i];
    sumConfidence += confidences[i];
  }
  return safeDivision(sumProduct, sumConfidence, 0);
}

export function calculateEarningsConcentration(history: any[]): number {
  if (!history || history.length === 0) return 0;
  const blocks: Record<string, number> = {};
  let total = 0;
  for (const h of history) {
    blocks[h.time_block] = (blocks[h.time_block] || 0) + h.earnings;
    total += h.earnings;
  }
  if (total === 0) return 0;

  // Find highest single block concentration ratio
  let maxConcentration = 0;
  for (const block in blocks) {
    const ratio = blocks[block] / total;
    if (ratio > maxConcentration) maxConcentration = ratio;
  }
  return maxConcentration;
}

import { TriggerOutput } from "./engineTypes";
import { TriggerEngineInputSchema } from "./engineValidators";
import { clamp, median, safeDivision } from "./scoringUtils";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function runTriggerEngine(inputRaw: any): TriggerOutput {
  const input = TriggerEngineInputSchema.parse(inputRaw);

  const signals = input.signals || [];

  // Normalization logic based on Type
  let baseTcs = 0;
  if (input.type === 'Heavy Rain') {
    // City threshold assumed at intensity 50mm=1.0 TCS
    baseTcs = clamp(input.intensity / 50, 0, 1);
  } else if (input.type === 'Internet Shutdown') {
    baseTcs = clamp(input.intensity / 100, 0, 1);
  } else {
    // Zone closure
    baseTcs = clamp(input.intensity / 80, 0, 1);
  }

  // Derive US (Uncertainty Score)
  // High variance in signals = higher uncertainty
  const rels = signals.map(s => s.reliability || 0.5);
  const medianRel = median(rels) || 0.8; // Assume 0.8 if no signals provided
  const US = clamp(1 - medianRel, 0, 1);

  // Derive TCS using reliability
  const TCS = clamp(baseTcs * (1 - (US * 0.3)), 0, 1);

  // Compute Exposure Score
  let exposure_score = 0.5; // default fallback
  if (input.workerActivity) {
    const { gpsConfidence, recentOrderRatio } = input.workerActivity;
    exposure_score = clamp((gpsConfidence * 0.6) + (recentOrderRatio * 0.4), 0, 1);
  }

  // Decision Matrix
  let decision = "MANUAL_REVIEW";
  if (TCS >= 0.85 && US <= 0.15) {
    decision = "AUTO_APPROVE";
  } else if (TCS >= 0.70 && US <= 0.30) {
    decision = "AUTO_APPROVE_LOW_CONFIDENCE";
  } else if (TCS < 0.3) {
    decision = "REJECT";
  }

  return {
    decision,
    TCS: Number(TCS.toFixed(4)),
    US: Number(US.toFixed(4)),
    exposure_score: Number(exposure_score.toFixed(4)),
    signals_json: signals,
    breakdown: {
      base_tcs: baseTcs,
      median_reliability: medianRel,
      missing_signal_penalty: Math.max(0, 3 - signals.length) * 0.05
    },
    explanation: `Calculated TCS of ${TCS.toFixed(2)} based on intensity ${input.intensity} for ${input.type}. Uncertainty evaluated at ${US.toFixed(2)} placing event in ${decision} matrix.`
  };
}
